#!/usr/bin/env python3
"""Shared Devin API HTTP client."""
import os
import sys
import requests


class DevinAPIClient:
    """Client for Devin API interactions."""

    def __init__(self):
        self.api_token = os.environ.get("DEVIN_API")
        if not self.api_token:
            print(
                '{"error": "DEVIN_API environment variable not set"}', file=sys.stderr
            )
            sys.exit(1)

        self.base_url = "https://api.devin.ai/v1"
        self.headers = {
            "Authorization": f"Bearer {self.api_token}",
            "Content-Type": "application/json",
        }

    def spawn_session(self, repo, task, context=None):
        """Spawn a new Devin session."""
        payload = {"repo": repo, "task": task}
        if context:
            payload["context"] = context

        try:
            response = requests.post(
                f"{self.base_url}/sessions",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {"error": str(e)}

    def get_session_status(self, session_id):
        """Get status of a Devin session."""
        try:
            response = requests.get(
                f"{self.base_url}/sessions/{session_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {"error": str(e)}

#!/usr/bin/env python3
"""Manage Devin knowledge notes (breadcrumbs) via the Devin API."""
import argparse
import json
import os
import sys
import requests


class DevinKnowledgeManager:
    """Client for managing Devin knowledge notes."""

    def __init__(self):
        self.api_token = os.environ.get("DEVIN_API")
        if not self.api_token:
            print(
                '{"error": "DEVIN_API environment variable not set"}', file=sys.stderr
            )
            sys.exit(1)

        self.base_url = "https://api.devin.ai/v1"
        self.headers = {
            "Authorization": f"Bearer {self.api_token}",
            "Content-Type": "application/json",
        }

    def get_knowledge(self, knowledge_id):
        """Retrieve a knowledge note by ID.

        Args:
            knowledge_id: The ID of the knowledge note.

        Returns:
            dict with the knowledge note content or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/knowledge/{knowledge_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_knowledge(self, knowledge_id, content):
        """Update a knowledge note by ID.

        Args:
            knowledge_id: The ID of the knowledge note.
            content: New content for the note.

        Returns:
            dict with success status or error.
        """
        payload = {"content": content}

        try:
            response = requests.patch(
                f"{self.base_url}/knowledge/{knowledge_id}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "knowledge_id": knowledge_id}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def create_knowledge(self, title, content, trigger_type="keyword", trigger=None):
        """Create a new knowledge note.

        Args:
            title: Title of the knowledge note.
            content: Content of the note.
            trigger_type: How the note is triggered ("keyword", "always", etc.).
            trigger: Trigger value (e.g., keyword string).

        Returns:
            dict with the created note or error.
        """
        payload = {
            "title": title,
            "content": content,
            "trigger_type": trigger_type,
        }
        if trigger:
            payload["trigger"] = trigger

        try:
            response = requests.post(
                f"{self.base_url}/knowledge",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def list_knowledge(self):
        """List all knowledge notes.

        Returns:
            dict with the list of notes or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/knowledge",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_breadcrumbs(self, target_ids, content):
        """Update multiple knowledge notes (breadcrumbs) with the same content.

        Args:
            target_ids: List of knowledge note IDs to update.
            content: Content to set on each note.

        Returns:
            dict with results for each target.
        """
        results = {}
        for kid in target_ids:
            results[kid] = self.update_knowledge(kid, content)
        return {
            "breadcrumb_results": results,
            "total": len(target_ids),
            "success_count": sum(
                1 for r in results.values() if r.get("success")
            ),
        }


def main():
    parser = argparse.ArgumentParser(description="Devin Knowledge Management CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    # list command
    subparsers.add_parser("list", help="List all knowledge notes")

    # get command
    get_parser = subparsers.add_parser("get", help="Get a knowledge note by ID")
    get_parser.add_argument("--id", required=True, help="Knowledge note ID")

    # create command
    create_parser = subparsers.add_parser("create", help="Create a knowledge note")
    create_parser.add_argument("--title", required=True, help="Note title")
    create_parser.add_argument("--content", required=True, help="Note content")
    create_parser.add_argument(
        "--trigger-type",
        default="keyword",
        help="Trigger type (default: keyword)",
    )
    create_parser.add_argument("--trigger", default=None, help="Trigger value")

    # update command
    update_parser = subparsers.add_parser("update", help="Update a knowledge note")
    update_parser.add_argument("--id", required=True, help="Knowledge note ID")
    update_parser.add_argument("--content", required=True, help="New content")

    # breadcrumbs command
    bc_parser = subparsers.add_parser(
        "breadcrumbs", help="Update multiple knowledge notes with the same content"
    )
    bc_parser.add_argument(
        "--targets",
        required=True,
        help="Comma-separated list of knowledge note IDs",
    )
    bc_parser.add_argument(
        "--content", required=True, help="Content to set on each note"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    manager = DevinKnowledgeManager()

    if args.command == "list":
        result = manager.list_knowledge()
    elif args.command == "get":
        result = manager.get_knowledge(args.id)
    elif args.command == "create":
        result = manager.create_knowledge(
            args.title, args.content, args.trigger_type, args.trigger
        )
    elif args.command == "update":
        result = manager.update_knowledge(args.id, args.content)
    elif args.command == "breadcrumbs":
        target_ids = [t.strip() for t in args.targets.split(",")]
        result = manager.update_breadcrumbs(target_ids, args.content)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Jira CLI for creating, updating, commenting, and searching tickets."""
import argparse
import json
import os
import sys
import requests


class JiraClient:
    """Client for Jira API interactions."""

    def __init__(self):
        self.base_url = os.environ.get("JIRA_BASE_URL", "").rstrip("/")
        if not self.base_url:
            print(
                '{"error": "JIRA_BASE_URL environment variable required"}',
                file=sys.stderr,
            )
            sys.exit(1)
        self.base_url = f"{self.base_url}/rest/api/3"

        jira_auth = os.environ.get("JIRA_AUTH")
        if jira_auth:
            self.headers = {
                "Authorization": f"Basic {jira_auth}",
                "Accept": "application/json",
                "Content-Type": "application/json",
            }
        else:
            jira_email = os.environ.get("JIRA_EMAIL")
            jira_token = os.environ.get("JIRA_API_TOKEN")
            if not jira_email or not jira_token:
                print(
                    '{"error": "JIRA_AUTH or (JIRA_EMAIL and JIRA_API_TOKEN) required"}',
                    file=sys.stderr,
                )
                sys.exit(1)

            import base64

            auth_str = f"{jira_email}:{jira_token}"
            auth_bytes = base64.b64encode(auth_str.encode()).decode()
            self.headers = {
                "Authorization": f"Basic {auth_bytes}",
                "Accept": "application/json",
                "Content-Type": "application/json",
            }

    def create_issue(self, project, summary, description, issue_type="Task"):
        """Create a new Jira issue."""
        payload = {
            "fields": {
                "project": {"key": project},
                "summary": summary,
                "description": {
                    "type": "doc",
                    "version": 1,
                    "content": [
                        {
                            "type": "paragraph",
                            "content": [{"type": "text", "text": description}],
                        }
                    ],
                },
                "issuetype": {"name": issue_type},
            }
        }

        try:
            response = requests.post(
                f"{self.base_url}/issue",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_issue(self, issue_key):
        """Get details of a Jira issue."""
        try:
            response = requests.get(
                f"{self.base_url}/issue/{issue_key}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def update_issue(self, issue_key, fields):
        """Update a Jira issue."""
        payload = {"fields": fields}

        try:
            response = requests.put(
                f"{self.base_url}/issue/{issue_key}",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return {"success": True, "issue_key": issue_key}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def add_comment(self, issue_key, comment):
        """Add a comment to a Jira issue."""
        payload = {
            "body": {
                "type": "doc",
                "version": 1,
                "content": [
                    {
                        "type": "paragraph",
                        "content": [{"type": "text", "text": comment}],
                    }
                ],
            }
        }

        try:
            response = requests.post(
                f"{self.base_url}/issue/{issue_key}/comment",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def search_issues(self, jql, max_results=50):
        """Search for Jira issues using JQL."""
        try:
            response = requests.get(
                f"{self.base_url}/search",
                headers=self.headers,
                params={"jql": jql, "maxResults": max_results},
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Jira CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    create_parser = subparsers.add_parser("create", help="Create a new issue")
    create_parser.add_argument(
        "--project", required=True, help="Project key (e.g., PROJ)"
    )
    create_parser.add_argument("--summary", required=True, help="Issue summary")
    create_parser.add_argument(
        "--description", required=True, help="Issue description"
    )
    create_parser.add_argument(
        "--type", default="Task", help="Issue type (default: Task)"
    )

    get_parser = subparsers.add_parser("get", help="Get issue details")
    get_parser.add_argument(
        "--issue-key", required=True, help="Issue key (e.g., PROJ-123)"
    )

    update_parser = subparsers.add_parser("update", help="Update an issue")
    update_parser.add_argument("--issue-key", required=True, help="Issue key")
    update_parser.add_argument("--summary", help="New summary")
    update_parser.add_argument("--description", help="New description")

    comment_parser = subparsers.add_parser("comment", help="Add a comment")
    comment_parser.add_argument("--issue-key", required=True, help="Issue key")
    comment_parser.add_argument("--comment", required=True, help="Comment text")

    search_parser = subparsers.add_parser("search", help="Search issues")
    search_parser.add_argument("--jql", required=True, help="JQL query")
    search_parser.add_argument(
        "--max-results", type=int, default=50, help="Max results"
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = JiraClient()

    if args.command == "create":
        result = client.create_issue(
            args.project, args.summary, args.description, args.type
        )
    elif args.command == "get":
        result = client.get_issue(args.issue_key)
    elif args.command == "update":
        fields = {}
        if args.summary:
            fields["summary"] = args.summary
        if args.description:
            fields["description"] = {
                "type": "doc",
                "version": 1,
                "content": [
                    {
                        "type": "paragraph",
                        "content": [{"type": "text", "text": args.description}],
                    }
                ],
            }
        result = client.update_issue(args.issue_key, fields)
    elif args.command == "comment":
        result = client.add_comment(args.issue_key, args.comment)
    elif args.command == "search":
        result = client.search_issues(args.jql, args.max_results)

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Notion CLI for querying and managing pages and databases."""
import argparse
import json
import os
import sys
import requests


class NotionClient:
    """Client for Notion API interactions."""

    def __init__(self):
        self.api_key = os.environ.get("NOTION_KEY")
        if not self.api_key:
            print(
                '{"error": "NOTION_KEY environment variable not set"}',
                file=sys.stderr,
            )
            sys.exit(1)

        self.base_url = "https://api.notion.com/v1"
        self.headers = {
            "Authorization": f"Bearer {self.api_key}",
            "Content-Type": "application/json",
            "Notion-Version": "2022-06-28",
        }

    def search(self, query, filter_type=None, page_size=20):
        """Search across all pages and databases the integration has access to.

        Args:
            query: Search query string.
            filter_type: Optional filter - "page" or "database".
            page_size: Number of results to return (default: 20, max: 100).

        Returns:
            dict with search results or error.
        """
        payload = {
            "query": query,
            "page_size": page_size,
        }
        if filter_type:
            payload["filter"] = {"value": filter_type, "property": "object"}

        try:
            response = requests.post(
                f"{self.base_url}/search",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_page(self, page_id):
        """Retrieve a Notion page by ID.

        Args:
            page_id: The Notion page ID (UUID, with or without dashes).

        Returns:
            dict with page properties or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/pages/{page_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def get_database(self, database_id):
        """Retrieve a Notion database schema by ID.

        Args:
            database_id: The Notion database ID (UUID, with or without dashes).

        Returns:
            dict with database schema/properties or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/databases/{database_id}",
                headers=self.headers,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def query_database(self, database_id, filter_dict=None, page_size=100):
        """Query a Notion database with optional filters.

        Args:
            database_id: The Notion database ID.
            filter_dict: Optional Notion filter object (see Notion API docs).
            page_size: Number of results to return (default: 100, max: 100).

        Returns:
            dict with query results or error.
        """
        payload = {"page_size": page_size}
        if filter_dict:
            payload["filter"] = filter_dict

        try:
            response = requests.post(
                f"{self.base_url}/databases/{database_id}/query",
                headers=self.headers,
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            return response.json()
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Notion CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    # search command
    search_parser = subparsers.add_parser(
        "search", help="Search pages and databases"
    )
    search_parser.add_argument("--query", required=True, help="Search query")
    search_parser.add_argument(
        "--filter-type",
        choices=["page", "database"],
        default=None,
        help="Filter results by type",
    )
    search_parser.add_argument(
        "--page-size",
        type=int,
        default=20,
        help="Number of results (default: 20, max: 100)",
    )

    # get-page command
    page_parser = subparsers.add_parser("get-page", help="Get a page by ID")
    page_parser.add_argument("--page-id", required=True, help="Notion page ID")

    # get-database command
    db_parser = subparsers.add_parser(
        "get-database", help="Get a database schema by ID"
    )
    db_parser.add_argument(
        "--database-id", required=True, help="Notion database ID"
    )

    # query-database command
    query_parser = subparsers.add_parser(
        "query-database", help="Query a database with optional filters"
    )
    query_parser.add_argument(
        "--database-id", required=True, help="Notion database ID"
    )
    query_parser.add_argument(
        "--filter",
        default=None,
        help="Notion filter as JSON string (see Notion API docs for filter format)",
    )
    query_parser.add_argument(
        "--page-size",
        type=int,
        default=100,
        help="Number of results (default: 100, max: 100)",
    )

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    client = NotionClient()

    if args.command == "search":
        result = client.search(
            args.query, filter_type=args.filter_type, page_size=args.page_size
        )
    elif args.command == "get-page":
        result = client.get_page(args.page_id)
    elif args.command == "get-database":
        result = client.get_database(args.database_id)
    elif args.command == "query-database":
        filter_dict = None
        if args.filter:
            try:
                filter_dict = json.loads(args.filter)
            except json.JSONDecodeError as e:
                print(
                    json.dumps({"error": f"Invalid JSON for --filter: {e}"}),
                    file=sys.stderr,
                )
                sys.exit(1)
        result = client.query_database(
            args.database_id, filter_dict=filter_dict, page_size=args.page_size
        )

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Generic Telegram notification tool via Bot API."""
import argparse
import json
import os
import sys
import requests


SEVERITY_EMOJI = {
    "INFO": "\u2139\ufe0f",
    "WARNING": "\u26a0\ufe0f",
    "CRITICAL": "\ud83d\udea8",
}


class TelegramNotifier:
    """Client for sending notifications via Telegram Bot API."""

    def __init__(self):
        self.bot_token = os.environ.get("TELEGRAM_BOT_TOKEN")
        if not self.bot_token:
            print(
                '{"error": "TELEGRAM_BOT_TOKEN environment variable not set"}',
                file=sys.stderr,
            )
            sys.exit(1)

        self.chat_id = os.environ.get("TELEGRAM_CHAT_ID")
        if not self.chat_id:
            print(
                '{"error": "TELEGRAM_CHAT_ID environment variable not set"}',
                file=sys.stderr,
            )
            sys.exit(1)

        self.base_url = f"https://api.telegram.org/bot{self.bot_token}"

    def send_message(self, text, parse_mode=None):
        """Send a plain text message to the configured chat.

        Args:
            text: Message text (up to 4096 characters).
            parse_mode: Optional parse mode - "HTML", "Markdown", or "MarkdownV2".

        Returns:
            dict with the API response or error.
        """
        payload = {
            "chat_id": self.chat_id,
            "text": text,
        }
        if parse_mode:
            payload["parse_mode"] = parse_mode

        try:
            response = requests.post(
                f"{self.base_url}/sendMessage",
                json=payload,
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            if data.get("ok"):
                return {
                    "success": True,
                    "message_id": data["result"]["message_id"],
                    "chat_id": self.chat_id,
                }
            return {"error": data.get("description", "Unknown Telegram API error")}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }

    def send_alert(self, title, fields_dict, severity="INFO", extra_context=None):
        """Send a formatted alert message with structured fields.

        Args:
            title: Alert title.
            fields_dict: Dictionary of field_name -> field_value pairs.
            severity: One of "INFO", "WARNING", "CRITICAL".
            extra_context: Optional additional text appended at the end.

        Returns:
            dict with the API response or error.
        """
        severity = severity.upper()
        emoji = SEVERITY_EMOJI.get(severity, SEVERITY_EMOJI["INFO"])

        lines = [f"{emoji} <b>{severity}: {title}</b>", ""]

        for key, value in fields_dict.items():
            lines.append(f"<b>{key}:</b> {value}")

        if extra_context:
            lines.append("")
            lines.append(extra_context)

        message = "\n".join(lines)
        return self.send_message(message, parse_mode="HTML")

    def get_bot_info(self):
        """Verify bot connectivity by calling getMe.

        Returns:
            dict with bot information or error.
        """
        try:
            response = requests.get(
                f"{self.base_url}/getMe",
                timeout=30,
            )
            response.raise_for_status()
            data = response.json()
            if data.get("ok"):
                bot = data["result"]
                return {
                    "success": True,
                    "bot_id": bot["id"],
                    "bot_name": bot.get("first_name", ""),
                    "bot_username": bot.get("username", ""),
                }
            return {"error": data.get("description", "Unknown Telegram API error")}
        except requests.exceptions.RequestException as e:
            return {
                "error": str(e),
                "status_code": getattr(e.response, "status_code", None),
            }


def main():
    parser = argparse.ArgumentParser(description="Telegram Notification CLI")
    subparsers = parser.add_subparsers(dest="command", help="Command to execute")

    # send command
    send_parser = subparsers.add_parser("send", help="Send a plain text message")
    send_parser.add_argument("--text", required=True, help="Message text")
    send_parser.add_argument(
        "--parse-mode",
        choices=["HTML", "Markdown", "MarkdownV2"],
        default=None,
        help="Parse mode for formatting",
    )

    # alert command
    alert_parser = subparsers.add_parser("alert", help="Send a formatted alert")
    alert_parser.add_argument("--title", required=True, help="Alert title")
    alert_parser.add_argument(
        "--fields",
        required=True,
        help='JSON object of field_name:value pairs (e.g., \'{"CPU": "95%%", "Host": "prod-1"}\')',
    )
    alert_parser.add_argument(
        "--severity",
        choices=["INFO", "WARNING", "CRITICAL"],
        default="INFO",
        help="Alert severity level (default: INFO)",
    )
    alert_parser.add_argument(
        "--context", default=None, help="Additional context text"
    )

    # info command
    subparsers.add_parser("info", help="Get bot info to verify connectivity")

    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        sys.exit(1)

    notifier = TelegramNotifier()

    if args.command == "send":
        result = notifier.send_message(args.text, parse_mode=args.parse_mode)
    elif args.command == "alert":
        try:
            fields = json.loads(args.fields)
        except json.JSONDecodeError as e:
            print(
                json.dumps({"error": f"Invalid JSON for --fields: {e}"}), file=sys.stderr
            )
            sys.exit(1)
        result = notifier.send_alert(
            args.title, fields, severity=args.severity, extra_context=args.context
        )
    elif args.command == "info":
        result = notifier.get_bot_info()

    print(json.dumps(result, indent=2))

    if "error" in result:
        sys.exit(1)
    sys.exit(0)


if __name__ == "__main__":
    main()

